mapper.select:
select delete_flag
from osh_question_answer_user_answer_vote
where user_id = #{userId}
and answer_id = #{answerId}

mapper.update:
update osh_question_answer_user_answer_vote
set delete_flag = 1, update_time = now(), update_by = #{updateBy}
where user_id = #{userId}
and answer_id = #{answerId}
